window.PACTO.acts["reg-2007-168"]={"label": "REGOLAMENTO (CE) N. 168/2007 DEL CONSIGLIO", "short": "Reg. 168/2007", "file": "ext-reg-2007-168.html", "external": true, "version": "consolidato 2022-04-27", "eurlex": "https://eur-lex.europa.eu/eli/reg/2007/168/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">È istituita l’Agenzia dell’Unione europea per i diritti fondamentali (di seguito «Agenzia»).</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "2": {"label": "Articolo 2", "heading": "Obiettivo", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">L’Agenzia ha lo scopo di fornire alle competenti istituzioni, organi e organismi dell’Unione e agli Stati membri, nell’attuazione del diritto dell’Unione, assistenza e consulenza in materia di diritti fondamentali in modo da aiutarli a rispettare pienamente tali diritti quando essi adottano misure o definiscono iniziative nei loro rispettivi settori di competenza.</p>"]]}, "3": {"label": "Articolo 3", "heading": "Ambito di applicazione", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini della realizzazione dell’obiettivo di cui all’articolo 2, l’Agenzia svolge la sua attività nell’ambito delle competenze dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nello svolgimento dei suoi compiti l’Agenzia fa riferimento ai diritti fondamentali di cui all’articolo 6 del trattato sull’Unione europea (TUE).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’Agenzia tratta questioni inerenti ai diritti fondamentali nell’Unione e negli Stati membri quando attuano il diritto dell’Unione, a eccezione degli atti o delle attività dell’Unione o degli Stati membri rientranti nella politica estera e di sicurezza comune o a essa connessi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "4": {"label": "Articolo 4", "heading": "Compiti", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per conseguire gli obiettivi di cui all’articolo 2 e nei limiti della competenza di cui all'articolo 3, l’Agenzia:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">raccoglie, registra, analizza e diffonde informazioni e dati rilevanti, obiettivi, attendibili e comparabili, compresi i risultati di ricerche e monitoraggio che le vsono comunicati dagli Stati membri, dalle istituzioni, dagli organi e degli organismi dell’Unione, dai centri di ricerca, da enti nazionali, da organizzazioni non governative, da paesi terzi e da organizzazioni internazionali, in particolare, dagli organi competenti del Consiglio d’Europa;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">predispone metodi e norme volti a migliorare la comparabilità, l’obiettività e l’attendibilità dei dati a livello europeo, in cooperazione con la Commissione e con gli Stati membri;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolge, collabora o incoraggia ricerche e indagini scientifiche, studi preparatori e di fattibilità, anche, se del caso e compatibilmente con le proprie priorità e con i propri programmi di lavoro annuale e pluriennale, a richiesta del Parlamento europeo, del Consiglio o della Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">formula e pubblica conclusioni e pareri su specifici aspetti tematici per le istituzioni dell’Unione e gli Stati membri quando danno attuazione al diritto dell’Unione, di propria iniziativa o a richiesta del Parlamento europeo, del Consiglio o della Commissione;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblica una relazione annuale sulle questioni inerenti ai diritti fondamentali che rientrano nei settori di azione dell'Agenzia, segnalando anche gli esempi di buone pratiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblica relazioni tematiche sulla base dei risultati delle sue analisi, delle sue ricerche e delle sue indagini;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblica una relazione annuale sulla sua attività; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">predispone una strategia di comunicazione e favorisce il dialogo con la società civile per sensibilizzare il vasto pubblico ai diritti fondamentali e informarlo attivamente sui suoi lavori.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le conclusioni, i pareri e le relazioni di cui al paragrafo 1 possono riguardare proposte della Commissione ai sensi dell’articolo 293 del trattato sul funzionamento dell’Unione europea (TFUE) o posizioni adottate dalle istituzioni nell’ambito delle procedure legislative solo qualora l’istituzione interessata abbia presentato una richiesta ai sensi del paragrafo 1, lettera d). Essi non riguardano la legittimità degli atti di cui all’articolo 263 TFUE né la questione se uno Stato membro abbia o no ottemperato a un obbligo che gli incombe in forza dei trattati ai sensi dell’articolo 258 TFUE.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il comitato scientifico è consultato prima dell’adozione della relazione di cui al paragrafo 1, lettera e).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’Agenzia presenta le relazioni di cui al paragrafo 1, lettere e) e g), entro il 15 giugno di ogni anno al Parlamento europeo, al Consiglio, alla Commissione, alla Corte dei conti, al Comitato economico e sociale europeo e al Comitato delle regioni.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "5": {"label": "Articolo 5", "heading": "Settori di attività", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">L’Agenzia svolge i propri compiti sulla base dei suoi programmi di lavoro annuale e pluriennale, che sono conformi alle risorse finanziarie e umane di cui dispone. Questa disposizione lascia impregiudicate le risposte dell’Agenzia alle richieste del Parlamento europeo, del Consiglio o della Commissione ai sensi dell’articolo 4, paragrafo 1, lettere c) e d), che non rientrano nei settori definiti dai programmi di lavoro annuale e pluriennale, purché le sue risorse finanziarie e umane lo consentano.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "5a": {"label": "Articolo 5 bis", "heading": "Programmazione annuale e pluriennale", "anchor": "art_5a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni anno il direttore redige un progetto di documento di programmazione contenente in particolare i programmi di lavoro annuale e pluriennale, conformemente all’articolo 32 del regolamento delegato (UE) 2019/715 della Commissione (\n<span class=\"superscript\">1</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il direttore presenta il progetto di documento di programmazione al consiglio di amministrazione. Il direttore presenta il progetto di documento di programmazione, approvato dal consiglio di amministrazione, al Parlamento europeo, al Consiglio e alla Commissione entro il 31 gennaio di ogni anno. In sede di Consiglio, il competente organo preparatorio discute il progetto di programma di lavoro pluriennale e può invitare l’Agenzia a presentare detto progetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il direttore presenta inoltre il progetto di documento di programmazione ai funzionari di nazionali di collegamento di cui all’articolo 8, paragrafo 1, e al comitato scientifico entro il 31 gennaio di ogni anno, al fine di consentire ai pertinenti Stati membri e al comitato scientifico di esprimere il loro parere sul progetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla luce dei risultati della discussione in seno al competente organo preparatorio del Consiglio e dei pareri ricevuti dalla Commissione, dagli Stati membri e dal comitato scientifico, il direttore presenta il progetto di documento di programmazione al consiglio di amministrazione per adozione. Il direttore presenta il documento di programmazione adottato al Parlamento europeo, al Consiglio, alla Commissione e ai funzionari nazionali di collegamento di cui all’articolo 8, paragrafo 1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Metodi di lavoro", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per garantire che siano fornite informazioni obiettive, attendibili e comparabili, l'Agenzia, basandosi sulle competenze di una vasta gamma di organizzazioni e di enti di ciascuno Stato membro e tenendo conto della necessità di coinvolgere le autorità nazionali nella raccolta dei dati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituisce e coordina reti di informazione e utilizza le reti esistenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">organizza riunioni di esperti esterni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">costituisce, se necessario, gruppi di lavoro ad hoc.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nello svolgimento delle sue attività l’Agenzia, a fini di complementarità e per garantire l’uso ottimale delle risorse, tiene conto, se del caso, delle informazioni raccolte e delle attività già effettuate in particolare:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">da istituzioni, organi e organismi dell’Unione, nonché da organi e organismi degli Stati membri;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dal Consiglio d'Europa riferendosi ai risultati e alle attività dei meccanismi di monitoraggio e di controllo del Consiglio d'Europa e del Commissario per i diritti dell'uomo del Consiglio d'Europa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dall'Organizzazione per la sicurezza e la cooperazione in Europa (OSCE), dalle Nazioni Unite e da altre organizzazioni internazionali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’Agenzia può instaurare rapporti contrattuali, in particolare stipulare contratti di subappalto, con altri organismi per l’esecuzione dei compiti che essa intenda loro affidare. L’Agenzia può inoltre concedere sovvenzioni per promuovere forme adeguate di cooperazione e di azioni comuni, in particolare con le organizzazioni nazionali ed internazionali di cui agli articoli 8 e 9.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "7": {"label": "Articolo 7", "heading": "Relazioni con gli organi e gli organismi competenti dell’Unione", "anchor": "art_7", "frags": [[null, "<p class=\"norm\">L’Agenzia provvede a un idoneo coordinamento delle sue attività con quelle degli organi e degli organismi dell’Unione. Le modalità della cooperazione sono specificate, se necessario, in protocolli d’intesa.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "8": {"label": "Articolo 8", "heading": "Cooperazione con organizzazioni a livello nazionale e internazionale", "anchor": "art_8", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro nomina un funzionario quale funzionario nazionale di collegamento.</div>\n</div>"], [null, "<p class=\"norm\">Il funzionario nazionale di collegamento costituisce il punto di contatto principale per l’Agenzia nello Stato membro.</p>"], [null, "<p class=\"norm\">L’Agenzia e i funzionari nazionali di collegamento collaborano in uno spirito di stretta e reciproca cooperazione.</p>"], [null, "<p class=\"norm\">L’Agenzia comunica ai funzionari nazionali di collegamento tutti i documenti elaborati conformemente all’articolo 4, paragrafo 1.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini dello svolgimento dei suoi compiti, l'Agenzia coopera con:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le organizzazioni governative e gli organi pubblici competenti in materia di diritti fondamentali a livello degli Stati membri, ivi comprese le istituzioni nazionali di difesa dei diritti dell'uomo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'Organizzazione per la sicurezza e la cooperazione in Europa (OSCE), in particolare l'Ufficio per le istituzioni democratiche e i diritti dell'uomo (ODIHR), le Nazioni Unite e altre organizzazioni internazionali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le modalità amministrative della cooperazione di cui al paragrafo 2 sono conformi al diritto dell’Unione e sono adottate dal consiglio di amministrazione sulla base del progetto presentato dal direttore, sentito il parere della Commissione. Se la Commissione esprime il proprio parere sfavorevole a tali modalità, il consiglio di amministrazione le riesamina e le adotta, modificandole ove necessario, a maggioranza dei due terzi dei suoi membri.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Cooperazione con il Consiglio d’Europa", "anchor": "art_9", "frags": [[null, "<p class=\"norm\">Per evitare duplicazioni e garantire la complementarietà e il valore aggiunto, l’Agenzia coordina le proprie attività con quelle del Consiglio d’Europa, con particolare riguardo ai programmi di lavoro annuale e pluriennale e alla cooperazione con la società civile di cui all’articolo 10.</p>"], [null, "<p class=\"norm\">A tal fine, l’Unione, secondo la procedura di cui all’articolo 218 TFUE, conclude un accordo con il Consiglio d’Europa allo scopo di stabilire una stretta collaborazione tra quest’ultimo e l’Agenzia. Tale accordo comprende la nomina da parte del Consiglio d’Europa di una personalità indipendente come membro del consiglio di amministrazione e dell’ufficio di presidenza dell’Agenzia in conformità degli articoli 12 e 13.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "10": {"label": "Articolo 10", "heading": "Cooperazione con la società civile; piattaforma dei diritti fondamentali", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'agenzia coopera strettamente con organizzazioni non governative e con istituzioni della società civile attive nel settore dei diritti fondamentali, ivi compresa la lotta contro il razzismo e la xenofobia a livello nazionale, europeo o internazionale. A tal fine l'agenzia stabilisce una rete di cooperazione («piattaforma dei diritti fondamentali») costituita da organizzazioni non governative per la difesa dei diritti dell'uomo, da sindacati e associazioni di datori di lavoro, da enti socioprofessionali competenti, da chiese, da associazioni religiose, filosofiche e non confessionali, da università, nonché da esperti qualificati di organizzazioni ed enti a livello europeo e internazionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La piattaforma dei diritti fondamentali costituisce un meccanismo di scambio di informazioni e di messa in comune di conoscenze. Essa assicura una stretta cooperazione tra l’Agenzia e le parti interessate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La piattaforma dei diritti fondamentali è aperta a tutte le parti interessate e competenti di cui al paragrafo 1. L'agenzia può rivolgersi ai membri della piattaforma dei diritti fondamentali in funzione delle esigenze specifiche relative a settori individuati come settori di attività prioritari dell'agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'agenzia incarica la piattaforma dei diritti fondamentali in particolare di:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">formulare proposte al consiglio di amministrazione sui programmi di lavoro annuale e pluriennale da adottare a norma dell’articolo 5 bis;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire un feedback e proporre al consiglio d'amministrazione il seguito da dare alla relazione annuale di cui all'articolo 4, paragrafo 1, lettera e);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">comunicare al direttore e al comitato scientifico i risultati e le raccomandazioni delle conferenze, dei seminari e delle riunioni pertinenti per i lavori dell'agenzia.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il coordinamento della piattaforma dei diritti fondamentali è assicurato sotto l'autorità del direttore.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "11": {"label": "Articolo 11", "heading": "Organi dell'Agenzia", "anchor": "art_11", "frags": [[null, "<p class=\"norm\">L’agenzia è composta da:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un consiglio di amministrazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un ufficio di presidenza;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un comitato scientifico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un direttore.</p>\n</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Consiglio di amministrazione", "anchor": "art_12", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consiglio di amministrazione è formato da persone con una solida conoscenza del settore dei diritti fondamentali e con un’adeguata esperienza nella gestione di organizzazioni pubbliche o private, incluse competenze amministrative e di bilancio, designate come segue:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una personalità indipendente nominata da ciascuno Stato membro che ricopre responsabilità di alto livello in seno ad un istituto nazionale indipendente nel settore dei diritti dell’uomo o di un'altra organizzazione del settore pubblico o privato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una personalità indipendente nominata dal Consiglio d’Europa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">due rappresentanti della Commissione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">Gli Stati membri, la Commissione e il Consiglio d’Europa si adoperano per realizzare una pari rappresentanza di donne e uomini in seno al consiglio di amministrazione.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascun membro del consiglio di amministrazione può farsi rappresentare da un supplente, il quale deve possedere i requisiti sopra precisati ed è nominato secondo la medesima procedura. L’Agenzia pubblica tiene aggiornato sul proprio sito web l’elenco dei membri del consiglio di amministrazione e dei loro supplenti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il mandato dei membri del consiglio di amministrazione e dei loro supplenti è di cinque anni. Un ex membro o supplente può essere rinominato per un mandato non consecutivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Oltre che per la normale procedura di sostituzione o per decesso, il mandato di un membro o di un supplente cessa solo in caso di dimissioni. Tuttavia, qualora un membro o un supplente non possieda più i requisiti di indipendenza, questi rassegna immediatamente le dimissioni e ne dà notifica alla Commissione e al direttore. In tali casi, oltre alla normale procedura di sostituzione, la parte interessata procede alla designazione di un nuovo membro o di un nuovo supplente per la durata restante del mandato. La parte interessata designa anche un nuovo membro o un nuovo supplente per la durata restante del mandato, se il consiglio di amministrazione stabilisce, su proposta di un terzo dei membri o della Commissione, che il membro o il supplente in questione non possiede più i requisiti di indipendenza. Se la durata restante del mandato è inferiore a due anni, il mandato del nuovo membro o supplente può essere prorogato per arrivare a un mandato completo di cinque anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione elegge tra i suoi membri nominati a norma del paragrafo 1, lettera a), del presente articolo, un presidente e un vicepresidente nonché gli altri due membri dell’ufficio di presidenza di cui all’articolo 13, paragrafo 1, con mandato di due anni e mezzo, rinnovabile una volta.</div>\n</div>"], [null, "<p class=\"norm\">Il presidente e il vicepresidente del consiglio di amministrazione sono eletti a maggioranza di due terzi dei membri del consiglio di amministrazione di cui al paragrafo 1, lettere a) e c), del presente articolo. Gli altri due membri dell’ufficio di presidenza di cui all’articolo 13, paragrafo 1, sono eletti a maggioranza dei membri del consiglio di amministrazione di cui al paragrafo 1, lettere a) e c), del presente articolo.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consiglio di amministrazione provvede affinché l’Agenzia esegua i compiti che ad essa vengono affidati. È l’organo di programmazione e di sorveglianza dell’Agenzia. In particolare, deve:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare i programmi di lavoro annuale e pluriennale dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare le relazioni annuali di cui all’articolo 4, paragrafo 1, lettere e) e g), nella quale ultima i risultati conseguiti vengono specificamente confrontati con gli obiettivi dei programmi di lavoro annuale e pluriennale;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nominare e, se necessario, revocare il direttore dell’Agenzia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare il progetto di bilancio e il bilancio annuale definitivo dell’Agenzia;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in conformità dei paragrafi 7 bis e 7 ter del presente articolo, esercitare, nei confronti del personale dell’Agenzia, i poteri conferiti dallo statuto dei funzionari dell’Unione europea («statuto del personale») e dal regime applicabile agli altri agenti dell’Unione («regime applicabile») di cui al regolamento (CEE, Euratom, CECA) n. 259/68 del Consiglio (\n<span class=\"superscript\">2</span>\n) all’autorità che ha il potere di nomina e all’autorità abilitata a concludere i contratti di assunzione, rispettivamente («poteri di autorità che ha il potere di nomina»);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare ogni anno uno stato di previsione delle entrate e delle spese dell’Agenzia e trasmetterlo alla Commissione, ai sensi dell'articolo 20, paragrafo 5;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare il regolamento interno dell’Agenzia sulla base di un progetto presentato dal direttore, previo parere della Commissione, del comitato scientifico e della personalità di cui al paragrafo 1, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare il regolamento finanziario applicabile all’Agenzia sulla base del progetto presentato dal direttore, previo parere della Commissione, ai sensi dell’articolo 21, paragrafo 11;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta le norme di applicazione dello statuto dei funzionari e del regime applicabile, conformemente all’articolo 110, paragrafo 2, dello statuto;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare disposizioni sulla trasparenza e l'accesso ai documenti, ai sensi dell’articolo 17, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nominare e revocare i membri del comitato scientifico, ai sensi dell'articolo 14, paragrafi 1 e 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilire che un membro del consiglio di amministrazione o un supplente non possiede più i requisiti di indipendenza ai sensi del paragrafo 4;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare una strategia di sicurezza, comprese norme sullo scambio di informazioni classificate UE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare norme per la prevenzione e la gestione dei conflitti di interesse in relazione ai suoi membri e ai membri del comitato scientifico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adottare e aggiornare regolarmente la strategia di comunicazione di cui all’articolo 4, paragrafo 1, lettera h).</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione può delegare all’ufficio di presidenza i suoi poteri, ad eccezione di quelli relativi alle materie di cui al paragrafo 6, lettere a), b), c), d), e), g), h), k) e l).</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7 bis.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta, in conformità dell’articolo 110, paragrafo 2, dello statuto dei funzionari, una decisione basata sull’articolo 2, paragrafo 1, dello statuto dei funzionari e sull’articolo 6 del regime applicabile, con cui delega al direttore i poteri di autorità che ha il potere di nomina e stabilisce le condizioni di sospensione della delega di poteri. Il direttore è autorizzato a subdelegare tali poteri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7 ter.  </span>\n<div class=\"norm inline-element\">Qualora circostanze eccezionali lo richiedano, il consiglio di amministrazione può, mediante decisione, sospendere temporaneamente la delega dei poteri di autorità che ha il potere di nomina delegati al direttore e quelli subdelegati da quest’ultimo ed esercitarli esso stesso o delegarli a uno dei suoi membri o a un membro del personale diverso dal direttore.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Di norma, le decisioni del consiglio di amministrazione sono adottate a maggioranza di tutti i membri.</div>\n</div>"], [null, "<p class=\"norm\">Le decisioni di cui al paragrafo 6, lettere da a) a e) e g), k) e l), sono adottate a maggioranza di due terzi di tutti i membri.</p>"], [null, "<p class=\"norm\">Le decisioni di cui all’articolo 25, paragrafo 2, sono adottate all’unanimità.</p>"], [null, "<p class=\"norm\">Ogni membro del consiglio di amministrazione o, in sua assenza, il supplente dispone di un voto. Il presidente esprime il voto decisivo.</p>"], [null, "<p class=\"norm\">La persona nominata dal Consiglio d’Europa può partecipare solo alle votazioni relative alle decisioni di cui al paragrafo 6, lettere a), b) e k).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il presidente convoca il consiglio di amministrazione due volte l’anno, ferma restando la possibilità di convocare riunioni straordinarie. Il presidente convoca le riunioni straordinarie di propria iniziativa o a richiesta della Commissione o di almeno un terzo dei membri del consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Il presidente o il vicepresidente del comitato scientifico e il direttore dell’Istituto europeo per l’uguaglianza di genere possono assistere alle riunioni del consiglio di amministrazione in qualità di osservatori. I direttori delle altre agenzie od organismi competenti dell’Unione e degli altri organismi internazionali menzionati agli articoli 8 e 9 possono parimenti assistervi in qualità di osservatori su invito dell’ufficio di presidenza.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Ufficio di presidenza", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione è assistito da un ufficio di presidenza. L’ufficio di presidenza sovrintende ai lavori preparatori necessari per l’adozione delle decisioni del consiglio di amministrazione. In particolare, esamina le questioni relative alle risorse di bilancio e umane.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre, l’ufficio di presidenza:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riesamina il documento di programmazione dell’Agenzia di cui all’articolo 5 bis su una base del progetto elaborato dal direttore, e lo presenta al consiglio di amministrazione per adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riesamina il progetto di bilancio annuale dell’Agenzia e lo presenta al consiglio di amministrazione per adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riesamina il progetto di relazione annuale sulle attività dell’Agenzia e lo presenta al consiglio di amministrazione per adozione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta una strategia antifrode per l’Agenzia, proporzionata ai rischi di frode, tenendo conto dei costi e dei benefici delle misure da attuare e sulla base di un progetto elaborato dal direttore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicura un seguito adeguato alle osservazioni e alle raccomandazioni risultanti dalle relazioni di audit e valutazioni interne ed esterne, e dalle indagini dell’Ufficio europeo per la lotta antifrode (OLAF) o della Procura europea (EPPO);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatte salve le responsabilità del direttore di cui all’articolo 15, paragrafo 4, assiste e consiglia il direttore in merito all’attuazione delle decisioni del consiglio di amministrazione, al fine di rafforzare il controllo della gestione amministrativa e di bilancio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ove necessario, per motivi di urgenza, l’ufficio di presidenza può prendere decisioni provvisorie per conto del consiglio di amministrazione, tra cui in materia di sospensione della delega dei poteri di autorità che ha il potere di nomina, in conformità delle condizioni di cui all’articolo 12, paragrafi 7 bis e 7 ter, e di questioni di bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’ufficio di presidenza è composto dal presidente e dal vicepresidente del consiglio di amministrazione, da due altri membri eletti dal consiglio di amministrazione in conformità dell’articolo 12, paragrafo 5, e da uno dei rappresentanti della Commissione in seno al consiglio di amministrazione.</div>\n</div>"], [null, "<p class=\"norm\">La persona nominata dal Consiglio d’Europa in seno al consiglio di amministrazione può partecipare alle riunioni dell’ufficio di presidenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’ufficio di presidenza è convocato dal presidente. Può essere convocato anche a richiesta di uno dei suoi membri. Esso adotta le sue decisioni a maggioranza dei suoi membri presenti. La persona nominata dal Consiglio d’Europa può partecipare alle votazioni sui punti riguardanti decisioni su cui detta persona ha diritto di voto in seno al consiglio di amministrazione conformemente all’articolo 12, paragrafo 8.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il direttore partecipa alle riunioni dell’ufficio di presidenza, senza diritto di voto.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "14": {"label": "Articolo 14", "heading": "Comitato scientifico", "anchor": "art_14", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il comitato scientifico si compone di undici personalità indipendenti particolarmente qualificate nel settore dei diritti fondamentali, dotate di competenze adeguate in materia di metodologie per la qualità e la ricerca scientifica. Il consiglio di amministrazione nomina gli undici membri e approva un elenco di riserva stabilito per ordine di merito secondo un invito a presentare candidature e una procedura di selezione trasparenti, previa consultazione della competente commissione del Parlamento europeo. Il consiglio di amministrazione garantisce l’equa rappresentanza geografica e si adopera per realizzare una pari rappresentanza di donne e uomini in seno al comitato scientifico. I membri del consiglio di amministrazione non sono membri del comitato scientifico. Il regolamento interno di cui all’articolo 12, paragrafo 6, lettera g), precisa le condizioni per la nomina del comitato scientifico.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il mandato dei membri del comitato scientifico è di cinque anni e non è rinnovabile.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I membri del comitato scientifico sono indipendenti. Possono essere sostituiti solo su loro richiesta o in caso di impossibilità permanente di esercitare le loro funzioni. Tuttavia, qualora un membro non possieda più i requisiti di indipendenza, questi rassegna immediatamente le dimissioni e ne dà notifica alla Commissione e al direttore. Alternativamente, il consiglio di amministrazione può dichiarare, su proposta di un terzo dei suoi membri o della Commissione, la mancanza di indipendenza e revocare la nomina della persona in questione. Il consiglio di amministrazione nomina la prima persona disponibile in ordine di merito sull’elenco di riserva per la durata restante del mandato. Nel caso in cui la durata restante del mandato sia inferiore a due anni, il mandato del nuovo membro può essere prorogato per un mandato completo di cinque anni. L’Agenzia pubblica e tiene aggiornato sul suo sito web l’elenco dei membri del comitato scientifico.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il comitato scientifico elegge il suo presidente e vicepresidente per un mandato di un anno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il comitato scientifico è il garante della qualità scientifica dei lavori dell'agenzia e orienta i lavori al riguardo. A tal fine, il direttore associa il comitato scientifico, non appena opportuno, alla preparazione di tutti i documenti elaborati conformemente all'articolo 4, paragrafo 1, lettere a), b), c), d), e), f) e h).</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">In particolare, il comitato scientifico consiglia il direttore e l’Agenzia in merito alla metodologia per la ricerca scientifica applicata nel lavoro dell’Agenzia.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il comitato scientifico delibera alla maggioranza di due terzi. È convocato dal presidente quattro volte all'anno. Se necessario, il presidente può avviare una procedura scritta o convoca riunioni straordinarie di propria iniziativa o a richiesta di almeno quattro membri del comitato scientifico.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Direttore", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia è posta sotto la direzione di un direttore nominato dal consiglio di amministrazione secondo la procedura di cooperazione («concertazione») prevista al paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm\">Il direttore è nominato sulla base dei propri meriti personali, della sua esperienza nel settore dei diritti fondamentali nonché delle sue capacità amministrative e di direzione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La procedura di cooperazione è la seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in base a un elenco predisposto dalla Commissione previo un invito a presentare candidature e una procedura di selezione trasparente, prima di invitare i candidati a un colloquio si chiede loro di prendere contatto con il Consiglio e con la Commissione competente del Parlamento europeo e di rispondere a un questionario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il Parlamento europeo e il Consiglio dell'Unione europea esprimeranno i rispettivi pareri e indicheranno i propri ordini di preferenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il Consiglio di amministrazione procede alla nomina del direttore tenendo conto dei suddetti pareri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il mandato del direttore è di cinque anni.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Nei dodici mesi che precedono la fine di tale mandato di cinque anni, la Commissione esegue una valutazione per tener conto in particolare:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle prestazioni del direttore;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">degli obblighi e delle necessità dell’Agenzia per il periodo futuro.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Il consiglio di amministrazione, su proposta della Commissione e alla luce della valutazione, può prorogare il mandato del direttore una volta per non più di cinque anni.</p>"], [null, "<p class=\"norm\">Il consiglio di amministrazione informa il Parlamento europeo e il Consiglio dell’intenzione di prorogare il mandato del direttore. Entro un mese prima che il consiglio di amministrazione prenda formalmente la decisione di prorogare il mandato del direttore, quest’ultimo può essere invitato a fare una dichiarazione dinanzi alla competente commissione del Parlamento europeo e rispondere alle domande dei membri di tale commissione.</p>"], [null, "<p class=\"norm\">Se il suo mandato non è prorogato, il direttore resta in carica fino alla nomina del suo successore.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il direttore è responsabile:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’assolvimento dei compiti di cui all’articolo 4, in particolare della preparazione e della pubblicazione dei documenti elaborati ai sensi dell’articolo 4, paragrafo 1, lettere da a) a h), in cooperazione con il comitato scientifico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elaborazione e dell’attuazione del documento di programmazione dell’Agenzia di cui all’articolo 5 bis;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle questioni riguardanti l’amministrazione corrente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’attuazione delle decisioni adottate dal consiglio di amministrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’esecuzione del bilancio dell’Agenzia, in conformità dell’articolo 21;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’attuazione di procedure efficaci di monitoraggio e valutazione delle prestazioni ottenute dall’Agenzia rispetto ai suoi obiettivi, secondo standard riconosciuti a livello professionale e indicatori di prestazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elaborazione di un piano d’azione volto a dare seguito alle conclusioni delle valutazioni retrospettive che analizzano la performance dei programmi e delle attività che comportano spese importanti, conformemente all’articolo 29 del regolamento delegato (UE) 2019/715;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della presentazione di una relazione annuale al consiglio di amministrazione sui risultati del sistema di monitoraggio e valutazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elaborazione di una strategia antifrode per l’Agenzia e della sua presentazione all’ufficio di presidenza per approvazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’elaborazione di un piano d’azione volto a dare seguito alle conclusioni delle relazioni di audit e valutazioni interne ed esterne, nonché delle indagini dell’OLAF, e della presentazione di una relazione sui progressi compiuti alla Commissione e al consiglio di amministrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della cooperazione con i funzionari nazionali di collegamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della cooperazione con la società civile, compreso il coordinamento della piattaforma dei diritti fondamentali ai sensi dell’articolo 10.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il direttore svolge i suoi compiti in piena indipendenza. Rende conto della gestione delle proprie attività al consiglio di amministrazione e assiste alle sue riunioni senza diritto di voto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il direttore può essere convocato in qualsiasi momento dal Parlamento europeo o dal Consiglio per un'audizione su questioni legate alle attività dell'agenzia.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il direttore può essere revocato prima della scadenza del mandato con decisione del consiglio di amministrazione, sulla base di una proposta di due terzi dei suoi membri o della Commissione, in caso di condotta scorretta, prestazioni insufficienti o irregolarità gravi o ripetute.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "16": {"label": "Articolo 16", "heading": "Indipendenza e interesse pubblico", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia assolve i suoi compiti in completa indipendenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I membri titolari e supplenti del consiglio di amministrazione, i membri del comitato scientifico e il direttore si impegnano ad agire nell’interesse pubblico. A tal fine essi rendono una dichiarazione d’interesse nella quale indicano l’assenza di interessi che possano essere considerati contrastanti con la loro indipendenza o interessi diretti o indiretti che possano essere considerati tali. La dichiarazione è resa per iscritto al momento di assumere l'incarico ed è riveduta se intervengono cambiamenti per quanto attiene agli interessi. Essa è pubblicata dall'Agenzia sul suo sito web.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Trasparenza e accesso ai documenti", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'Agenzia mette a punto buone prassi amministrative che garantiscano la massima trasparenza possibile per quanto concerne le sue attività.</div>\n</div>"], [null, "<p class=\"norm\">Il regolamento (CE) n. 1049/2001 si applica ai documenti in possesso dell’Agenzia.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Entro sei mesi dall’entrata in funzione dell’Agenzia, il consiglio di amministrazione adotta norme specifiche per l'attuazione pratica del paragrafo 1. Queste comprendono tra l'altro norme per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la pubblicità delle riunioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la pubblicazione dei lavori dell'agenzia, tra cui quelli del comitato scientifico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">disposizioni per l'attuazione del regolamento (CE) n. 1049/2001.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le decisioni adottate dall’Agenzia sulla base dell’articolo 8 del regolamento (CE) n. 1049/2001 possono essere oggetto di una denuncia presso il Mediatore o di un ricorso dinanzi alla Corte di giustizia dell’Unione europea (Corte di giustizia), ai sensi rispettivamente degli articoli 228 e 263 TFUE.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "18": {"label": "Articolo 18", "heading": "Protezione dei dati", "anchor": "art_18", "frags": [[null, "<p class=\"norm\">Il regolamento (CE) n. 45/2001 si applica all'Agenzia.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "19": {"label": "Articolo 19", "heading": "Riesame del Mediatore", "anchor": "art_19", "frags": [[null, "<p class=\"norm\">L’operato dell’Agenzia è sottoposto al controllo del Mediatore a norma dell’articolo 228 TFUE.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "20": {"label": "Articolo 20", "heading": "Formazione del bilancio", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Tutte le entrate e le spese dell’Agenzia formano oggetto di previsioni per ciascun esercizio finanziario, che coincide con l’anno civile, e sono iscritte nel bilancio dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel bilancio dell’Agenzia, entrate e spese risultano in pareggio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le entrate dell’Agenzia comprendono, a prescindere da altre risorse, un contributo dell’Unione iscritto nel bilancio generale dell’Unione (sezione «Commissione»).</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm inline-element\">Tali entrate possono essere integrate da:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pagamenti ricevuti come corrispettivi di servizi resi nel quadro della realizzazione dei compiti di cui all'articolo 4;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contributi finanziari delle organizzazioni o dei paesi di cui agli articoli 8, 9 e 28.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le spese dell’Agenzia comprendono le retribuzioni del personale, le spese amministrative e di infrastruttura e le spese di esercizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ogni anno, il consiglio di amministrazione, sulla base di un progetto stabilito dal direttore, elabora lo stato di previsione delle entrate e delle spese dell’Agenzia per l’esercizio successivo. Entro il 31 marzo il consiglio di amministrazione trasmette alla Commissione lo stato di previsione, accompagnato da un progetto di tabella dell’organico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione trasmette lo stato di previsione al Parlamento europeo e al Consiglio (di seguito «autorità di bilancio») unitamente al progetto preliminare di bilancio dell’Unione europea.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Sulla base dello stato di previsione, la Commissione inserisce nel progetto preliminare di bilancio generale dell’Unione europea la stima che ritiene necessaria per la tabella dell’organico e la quota della sovvenzione a carico del bilancio generale che essa trasmette all’autorità di bilancio ai sensi dell’articolo 314 TFUE.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L’autorità di bilancio autorizza gli stanziamenti a titolo della sovvenzione destinata all’Agenzia. L’autorità di bilancio adotta la tabella dell’organico per l’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione adotta il bilancio dell'Agenzia. Esso diventa definitivo dopo l’adozione definitiva del bilancio generale dell’Unione europea. Se del caso, si procede agli opportuni adeguamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione comunica quanto prima all’autorità di bilancio la sua intenzione di realizzare qualsiasi progetto che possa avere incidenze finanziarie significative sul finanziamento del bilancio dell'Agenzia, in particolare i progetti di natura immobiliare, quali l’affitto o l’acquisto di edifici. Esso ne informa la Commissione.</div>\n</div>"], [null, "<p class=\"norm\">Qualora un ramo dell’autorità di bilancio comunichi che intende emettere un parere, tale parere è trasmesso al consiglio di amministrazione entro un termine di sei settimane dalla notifica del progetto.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Esecuzione del bilancio", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il direttore cura l'esecuzione del bilancio dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> marzo successivo alla chiusura dell’esercizio, il contabile dell’Agenzia comunica i conti provvisori, insieme alla relazione sulla gestione finanziaria e di bilancio dell’esercizio, al contabile della Commissione. Il contabile della Commissione consolida i conti provvisori delle istituzioni e degli organismi decentrati ai sensi dell’articolo 128 del regolamento (CE, Euratom) n. 1605/2002 del Consiglio (\n<span class=\"superscript\">3</span>\n) (di seguito «regolamento finanziario»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 31 marzo successivo alla chiusura dell’esercizio, il contabile della Commissione trasmette i conti provvisori dell’Agenzia, insieme alla relazione sulla gestione finanziaria e di bilancio dell’esercizio, alla Corte dei conti. La relazione sulla gestione finanziaria e di bilancio è trasmessa anche al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Una volta ricevute le osservazioni della Corte dei conti sui conti provvisori dell’Agenzia, ai sensi dell’articolo 129 del regolamento finanziario, il direttore redige i conti definitivi dell’Agenzia sotto la propria responsabilità e li trasmette per parere al consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione formula un parere sui conti definitivi dell’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> luglio successivo alla chiusura dell’esercizio finanziario, il direttore trasmette i conti definitivi, corredati del parere del consiglio di amministrazione, al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I conti definitivi sono pubblicati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il direttore invia alla Corte dei conti, entro il 30 settembre, una risposta alle sue osservazioni e la trasmette anche al consiglio di amministrazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il direttore presenta al Parlamento europeo, su richiesta di quest’ultimo e a norma dall’articolo 146, paragrafo 3, del regolamento finanziario, tutte le informazioni necessarie al corretto svolgimento della procedura di discarico per l’esercizio in oggetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, dà discarico al direttore, anteriormente al 30 aprile dell’anno «n+2», dell’esecuzione del bilancio dell’esercizio «n».</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Le disposizioni finanziarie applicabili all’Agenzia sono adottate dal consiglio di amministrazione previa consultazione della Commissione. Tali disposizioni non possono discostarsi dal regolamento (CE, Euratom) n. 2343/2002, a meno che ciò si renda specificamente necessario ai fini del funzionamento dell’Agenzia e previo consenso della Commissione.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Lotta alle frodi", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al fine di combattere la frode, la corruzione e altre attività illecite, si applicano senza restrizioni all’Agenzia le disposizioni del regolamento (CE) n. 1073/1999.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia aderisce all’accordo interistituzionale, del 25 maggio 1999, tra il Parlamento europeo, il Consiglio dell'Unione europea e la Commissione delle Comunità europee relativo alle indagini interne svolte dall’Ufficio europeo per la lotta antifrode (OLAF) (\n<span class=\"superscript\">4</span>\n), e adotta quanto prima le disposizioni adeguate applicabili all’insieme del suo personale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le decisioni in materia di finanziamento, nonché gli accordi e gli strumenti di esecuzione che ne conseguono, prevedono espressamente la possibilità che la Corte dei conti e l’OLAF effettuino, se del caso, controlli in loco presso i beneficiari di finanziamenti dell’Agenzia e presso gli agenti incaricati della ripartizione di tali finanziamenti.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "23": {"label": "Articolo 23", "heading": "Natura giuridica e sede", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia ha personalità giuridica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia gode in tutti gli Stati membri della più ampia capacità giuridica riconosciuta alle persone giuridiche dalle legislazioni nazionali. In particolare, essa può acquistare e alienare beni mobili e immobili e stare in giudizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’Agenzia è rappresentata dal suo direttore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’Agenzia subentra in tutti i rapporti giuridici instaurati dall’Osservatorio europeo dei fenomeni di razzismo e xenofobia. Essa assume tutti i diritti e gli obblighi di natura giuridica nonché tutti gli impegni finanziari dell’Osservatorio. I contratti di lavoro conclusi dall’Osservatorio prima dell’adozione del presente regolamento sono onorati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’Agenzia ha sede a Vienna.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "24": {"label": "Articolo 24", "heading": "Personale", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al personale dell’Agenzia e al suo direttore si applicano lo statuto dei funzionari e il regime applicabile e le norme adottate congiuntamente dalle istituzioni dell’Unione ai fini dell’applicazione di questo statuto e di questo regime.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il consiglio di amministrazione può adottare disposizioni che consentano di assumere esperti nazionali distaccati dagli Stati membri presso l’Agenzia.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "25": {"label": "Articolo 25", "heading": "Regime linguistico", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le disposizioni del regolamento n. 1 del 15 aprile 1958 si applicano all’Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Consiglio di amministrazione decide riguardo al regime linguistico interno all'Agenzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I servizi di traduzione necessari per il funzionamento dell’Agenzia sono forniti dal Centro di traduzione degli organismi dell’Unione europea.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "26": {"label": "Articolo 26", "heading": "Privilegi e immunità", "anchor": "art_26", "frags": [[null, "<p class=\"norm\">Il protocollo n. 7 sui privilegi e sulle immunità dell’Unione europea, allegato al TUE e al TFUE si applica all’Agenzia.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "27": {"label": "Articolo 27", "heading": "Competenza della Corte di giustizia", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La responsabilità contrattuale dell’Agenzia è disciplinata dalla normativa applicabile al contratto di cui trattasi.</div>\n</div>"], [null, "<p class=\"norm\">La Corte di giustizia è competente a decidere in forza d’una clausola compromissoria contenuta nei contratti stipulati dall’Agenzia.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In materia di responsabilità extracontrattuale, l’Agenzia deve risarcire, conformemente ai principi generali comuni ai diritti degli Stati membri, i danni cagionati dall’Agenzia o dai suoi agenti nell’esercizio delle loro funzioni.</div>\n</div>"], [null, "<p class=\"norm\">La Corte di giustizia è competente a conoscere delle controversie in materia di risarcimento del danno.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Corte di giustizia è competente a pronunciarsi sui ricorsi proposti contro l’Agenzia, alle condizioni previste agli articoli 263 e 265 TFUE.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "28": {"label": "Articolo 28", "heading": "Partecipazione di paesi candidati e dei paesi con cui è stato concluso un accordo di stabilizzazione e di associazione e portata di tale partecipazione", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia è aperta alla partecipazione, in qualità di osservatori, di paesi candidati.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La partecipazione di cui al paragrafo 1 e le pertinenti modalità sono stabilite con decisione del pertinente consiglio di associazione, tenuto conto dello status specifico di ciascun paese. Tale decisione stabilisce la natura, la portata e le modalità della partecipazione di detti paesi ai lavori dell’Agenzia, nel quadro fissato agli articoli 4 e 5, comprese le disposizioni relative alla partecipazione alle iniziative avviate dall’Agenzia, ai contributi finanziari e al personale. La decisione è conforme alle disposizioni del presente regolamento e allo statuto dei funzionari d e al regime applicabile. Essa dispone che il paese partecipante possa nominare una personalità indipendente, che soddisfi i requisiti in materia di qualificazioni previsti all’articolo 12, paragrafo 1, lettera a), in qualità di osservatore senza diritto di voto nel consiglio di amministrazione. Su decisione del consiglio di associazione l’Agenzia può trattare questioni inerenti ai diritti fondamentali nel quadro dell’articolo 3, paragrafo 1, nel pertinente paese, nella misura necessaria ai fini dell’allineamento progressivo del diritto di detto paese al diritto dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il Consiglio, deliberando all’unanimità su proposta della Commissione, può decidere di invitare un paese con il quale l’Unione europea ha concluso un accordo di stabilizzazione e di associazione a partecipare all’Agenzia in qualità di osservatore. In tal caso si applicano le disposizioni del paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "30": {"label": "Articolo 30", "heading": "Valutazioni e riesame", "anchor": "art_30", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia effettua regolari valutazioni ex ante ed ex post delle sue attività che comportano spese ingenti. Il direttore comunica al consiglio di amministrazione i risultati di dette valutazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia trasmette ogni anno all’autorità di bilancio qualsiasi informazione utile riguardante i risultati delle procedure di valutazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro 28 aprile 2027 e successivamente ogni cinque anni, la Commissione fa eseguire una valutazione per stabilire, in particolare, l’impatto, l’efficacia e l’efficienza dell’Agenzia e delle sue prassi di lavoro. La valutazione tiene conto dei pareri del consiglio di amministrazione e delle altre parti in causa a livello sia dell’Unione che nazionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Una valutazione su due di cui al paragrafo 3 comprende anche una valutazione dei risultati ottenuti dall’Agenzia, tenuto conto degli obiettivi, del mandato e dei compiti. La valutazione può esaminare, in particolare, l’eventuale necessità di modificare il mandato dell’Agenzia nonché le implicazioni finanziarie di siffatta modifica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione presenta le conclusioni della valutazione di cui al paragrafo 3 al consiglio di amministrazione. Il consiglio di amministrazione esamina le conclusioni della valutazione e indirizza alla Commissione le raccomandazioni ritenute necessarie concernenti le modifiche da apportare all’Agenzia, alle sue prassi di lavoro e alla portata della sua missione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione presenta al Parlamento europeo e al Consiglio una relazione in merito ai risultati della valutazione di cui al paragrafo 3 e alle raccomandazioni del consiglio di amministrazione di cui al paragrafo 5. I risultati di tale valutazione e tali raccomandazioni sono resi pubblici.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "32": {"label": "Articolo 32", "heading": "Inizio dell’attività dell’Agenzia", "anchor": "art_32", "frags": [[null, "<p class=\"norm\">L’Agenzia è operativa a decorrere dal 1<span class=\"superscript\">o</span> marzo 2007.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Abrogazione", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il regolamento (CE) n. 1035/97 è abrogato a decorrere dal 1<span class=\"superscript\">o</span> marzo 2007.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I riferimenti al regolamento abrogato si intendono fatti al presente regolamento.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Entrata in vigore e applicazione", "anchor": "art_34", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"], [null, "<p class=\"norm\">Esso si applica a decorrere dal 1<span class=\"superscript\">o</span> marzo 2007.</p>"], [null, "<p class=\"norm\">Il presente regolamento è obbligatorio in tutti i suoi elementi e direttamente applicabile in ciascuno degli Stati membri.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">1</span>\n) Regolamento delegato (UE) 2019/715 della Commissione, del 18 dicembre 2018, relativo al regolamento finanziario quadro degli organismi istituiti in virtù del TFUE e del trattato Euratom, di cui all’articolo 70 del regolamento (UE, Euratom) 2018/1046 del Parlamento europeo e del Consiglio (GU L 122 del 10.5.2019, pag. 1).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">2</span>\n) GU L 56 del 4.3.1968, pag. 1.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">3</span>\n) GU L 248 del 16.9.2002, pag. 1. Regolamento modificato dal regolamento (CE, Euratom) n. 1995/2006 (GU L 390 del 30.12.2006, pag. 1).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">4</span>\n) GU L 136 del 31.5.1999, pag. 15.</p>"]]}}, "recitals": {}};